export interface StoreAPI {
    get(key: string, optionalDefaultValue?: any): any;
    set(key: string, value: any): any;
    del(key: string): any;
}
declare type RequireAtLeastOne<T, Keys extends keyof T = keyof T> = Pick<T, Exclude<keyof T, Keys>> & {
    [K in Keys]-?: Required<Pick<T, K>> & Partial<Pick<T, Exclude<Keys, K>>>;
}[Keys];
declare type Attrs = {
    [key: string]: any;
};
export declare type trackEvent = (name: string, attrs: Attrs) => void;
export declare type Mode = 'normal' | 'test' | 'gray';
export declare type FormatType = 'merged' | 'splitted';
export declare type RequestFn = (url: string, options: {
    timeout: number;
}) => Promise<Response>;
export interface IAfterLoadPlugin {
    type: string;
    process(text: Texts, options: Options): Promise<Texts>;
}
interface CommonOptions {
    namespace: string | Array<string>;
    api_key: string;
    apiKey: string;
    store?: StoreAPI;
    request: RequestFn;
    /**
     * 指定文案拉取的环境
     * normal 线上环境，test 测试环境，gray 灰度环境
     */
    mode?: Mode;
    /**
     * 是否启用测试环境
     */
    test?: boolean;
    /**
     * 最终返回文案的格式
     * merged 所有空间的文案全部合并到一个 map
     * splitted 每个空间的文案单独返回
     */
    format?: FormatType;
    locale?: string;
    timeout?: number;
    lazyUpdate?: boolean;
    fallbackLang?: Array<string>;
    tracker?: trackEvent;
    /**
     * 自定义发布版本
     * 有则根据对应版本拉取文案
     * 无则拉取最新版本的文案
     * 重：需要和namespace一一对应
     *
     * 支持格式
     * 1.字符串 1.0.0，namespace也为字符串
     * 2.数组 ['1.0.0']，namespace也为数组并一一对应
     * 3.对象 { name: '1.0.0' }，key为空间名称，设计这个格式的目的：担心用户有的空间走固定版本有的默认最新版本，这样设置就不需要管namespace顺序问题
     */
    version?: string | string[] | {
        [key: string]: string;
    };
    plugins?: Array<IAfterLoadPlugin>;
    cache?: boolean;
    /** 是否开启debug模式，如果开启会在控制台打印所有的文案 */
    debug?: boolean;
    /** 接口请求失败时是否返回缓存文案而非抛错，默认 false */
    fallbackToCache?: boolean;
}
interface BaseOptionsWithCDN extends CommonOptions {
    cdn: string;
    zoneHost?: string;
}
interface BaseOptionsWithoutCDN extends CommonOptions {
    cdn?: undefined;
    /**
     * 指定域名，地区对应域名可查看:
     * https://bytedance.feishu.cn/wiki/wikcnrILBFaGcjbYQkfAFPljqsg#9CAlE8
     * 当支持 cdn 时，zoneHost 为可选，同时存在时优先走cdn 获取逻辑
     */
    zoneHost: string;
}
declare type BaseOptions = BaseOptionsWithCDN | BaseOptionsWithoutCDN;
export declare type Options = RequireAtLeastOne<BaseOptions, 'api_key' | 'apiKey'>;
export declare type Response = {
    data: {
        message: any;
        status: number;
    };
};
export declare type Version = string;
export declare type Namspae = string;
export declare type Texts = {
    [k: string]: string;
};
export declare function createOptions(options: Options): RequireAtLeastOne<BaseOptions, "api_key" | "apiKey">;
export {};
